import { z } from "zod";
import { prisma } from "../config/prisma.js";
import { idParams } from "../validators/common.js";
const productId = z.object({ productId: z.string().cuid() });
const cartInput = z.object({ productId: z.string().cuid(), quantity: z.number().int().min(1).max(100) });
export const listWishlist = async (req, res) => { res.json({ data: await prisma.wishlistItem.findMany({ where: { userId: req.auth.userId }, include: { product: { include: { images: { include: { media: true } } } } } }) }); };
export const addWishlist = async (req, res) => { const { productId: pid } = productId.parse(req.body); const item = await prisma.wishlistItem.upsert({ where: { userId_productId: { userId: req.auth.userId, productId: pid } }, update: {}, create: { userId: req.auth.userId, productId: pid } }); res.status(201).json({ data: item }); };
export const removeWishlist = async (req, res) => { await prisma.wishlistItem.delete({ where: { userId_productId: { userId: req.auth.userId, productId: idParams.parse(req.params).id } } }); res.status(204).end(); };
export const listCart = async (req, res) => { res.json({ data: await prisma.cartItem.findMany({ where: { userId: req.auth.userId }, include: { product: { include: { images: { include: { media: true } } } } } }) }); };
export const setCart = async (req, res) => { const input = cartInput.parse(req.body); const item = await prisma.cartItem.upsert({ where: { userId_productId: { userId: req.auth.userId, productId: input.productId } }, update: { quantity: input.quantity }, create: { ...input, userId: req.auth.userId } }); res.json({ data: item }); };
export const removeCart = async (req, res) => { await prisma.cartItem.delete({ where: { userId_productId: { userId: req.auth.userId, productId: idParams.parse(req.params).id } } }); res.status(204).end(); };
